CREATE TABLE public.blocked_emails (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, pattern TEXT NOT NULL UNIQUE, type TEXT NOT NULL CHECK (type IN ('email','domain')), reason TEXT, created_by UUID, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_blocked_emails_pattern ON public.blocked_emails(lower(pattern)); CREATE INDEX idx_blocked_emails_type ON public.blocked_emails(type); ALTER TABLE public.blocked_emails ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins manage blocked_emails" ON public.blocked_emails FOR ALL USING (public.has_role(auth.uid(),'admin'::app_role)) WITH CHECK (public.has_role(auth.uid(),'admin'::app_role)); INSERT INTO public.blocked_emails (pattern, type, reason) VALUES ('mailinator.com','domain','Disposable'),('tempmail.com','domain','Disposable'),('temp-mail.org','domain','Disposable'),('10minutemail.com','domain','Disposable'),('guerrillamail.com','domain','Disposable'),('guerrillamail.info','domain','Disposable'),('sharklasers.com','domain','Disposable'),('yopmail.com','domain','Disposable'),('throwawaymail.com','domain','Disposable'),('getnada.com','domain','Disposable'),('maildrop.cc','domain','Disposable'),('trashmail.com','domain','Disposable'),('fakeinbox.com','domain','Disposable'),('mailnesia.com','domain','Disposable'),('mintemail.com','domain','Disposable'),('dispostable.com','domain','Disposable'),('moakt.com','domain','Disposable'),('mohmal.com','domain','Disposable'),('emailondeck.com','domain','Disposable'),('spam4.me','domain','Disposable'),('mailcatch.com','domain','Disposable'),('inboxbear.com','domain','Disposable'),('tempr.email','domain','Disposable'),('mytrashmail.com','domain','Disposable'),('discard.email','domain','Disposable') ON CONFLICT (pattern) DO NOTHING; CREATE OR REPLACE FUNCTION public.is_email_blocked(_email TEXT) RETURNS BOOLEAN LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $func$ SELECT EXISTS (SELECT 1 FROM public.blocked_emails WHERE (type='email' AND lower(pattern)=lower(_email)) OR (type='domain' AND lower(_email) LIKE '%@' || lower(pattern))) $func$; CREATE TABLE public.admin_access_logs (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, admin_id UUID NOT NULL, action TEXT NOT NULL, ip_address TEXT, user_agent TEXT, path TEXT, metadata JSONB DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_admin_access_logs_admin_date ON public.admin_access_logs(admin_id, created_at DESC); CREATE INDEX idx_admin_access_logs_action ON public.admin_access_logs(action); CREATE INDEX idx_admin_access_logs_created ON public.admin_access_logs(created_at DESC); ALTER TABLE public.admin_access_logs ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins view access logs" ON public.admin_access_logs FOR SELECT USING (public.has_role(auth.uid(),'admin'::app_role)); CREATE POLICY "Admins insert own access logs" ON public.admin_access_logs FOR INSERT WITH CHECK (public.has_role(auth.uid(),'admin'::app_role) AND admin_id = auth.uid()); CREATE TABLE public.login_attempts (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, email TEXT NOT NULL, ip_address TEXT, success BOOLEAN NOT NULL DEFAULT false, attempted_at TIMESTAMPTZ NOT NULL DEFAULT now()); CREATE INDEX idx_login_attempts_email_time ON public.login_attempts(lower(email), attempted_at DESC); CREATE INDEX idx_login_attempts_ip_time ON public.login_attempts(ip_address, attempted_at DESC) WHERE ip_address IS NOT NULL; ALTER TABLE public.login_attempts ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins view login attempts" ON public.login_attempts FOR SELECT USING (public.has_role(auth.uid(),'admin'::app_role)); CREATE OR REPLACE FUNCTION public.check_login_rate_limit(_email TEXT, _max_attempts INT DEFAULT 5, _window_minutes INT DEFAULT 15) RETURNS JSONB LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path = public AS $func$ DECLARE failed_count INT; oldest_attempt TIMESTAMPTZ; BEGIN SELECT COUNT(*), MIN(attempted_at) INTO failed_count, oldest_attempt FROM public.login_attempts WHERE lower(email)=lower(_email) AND success=false AND attempted_at > now() - (_window_minutes || ' minutes')::interval; IF failed_count >= _max_attempts THEN RETURN jsonb_build_object('blocked', true, 'failed_attempts', failed_count, 'retry_after_seconds', GREATEST(1, EXTRACT(EPOCH FROM (oldest_attempt + (_window_minutes || ' minutes')::interval - now()))::int)); END IF; RETURN jsonb_build_object('blocked', false, 'failed_attempts', failed_count); END; $func$; CREATE INDEX IF NOT EXISTS idx_trial_bookings_email_created ON public.trial_bookings(lower(email), created_at DESC); CREATE INDEX IF NOT EXISTS idx_contact_submissions_email_created ON public.contact_submissions(lower(email), created_at DESC); CREATE OR REPLACE FUNCTION public.cleanup_old_logs() RETURNS JSONB LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $func$ DECLARE analytics_deleted INT; pageviews_deleted INT; admin_deleted INT; login_deleted INT; BEGIN DELETE FROM public.analytics_events WHERE created_at < now() - interval '30 days'; GET DIAGNOSTICS analytics_deleted = ROW_COUNT; DELETE FROM public.page_views WHERE entered_at < now() - interval '30 days'; GET DIAGNOSTICS pageviews_deleted = ROW_COUNT; DELETE FROM public.admin_access_logs WHERE created_at < now() - interval '90 days'; GET DIAGNOSTICS admin_deleted = ROW_COUNT; DELETE FROM public.login_attempts WHERE attempted_at < now() - interval '7 days'; GET DIAGNOSTICS login_deleted = ROW_COUNT; RETURN jsonb_build_object('analytics_events', analytics_deleted, 'page_views', pageviews_deleted, 'admin_access_logs', admin_deleted, 'login_attempts', login_deleted, 'cleaned_at', now()); END; $func$; DO $outer$ BEGIN IF EXISTS (SELECT 1 FROM pg_extension WHERE extname='pg_cron') THEN PERFORM cron.unschedule(jobid) FROM cron.job WHERE jobname='cleanup-old-logs-nightly'; PERFORM cron.schedule('cleanup-old-logs-nightly', '0 3 * * *', 'SELECT public.cleanup_old_logs();'); END IF; END $outer$;